import os
import sqlite3


class FileAccess:
    def __init__(self):
        self._db = 'fileaccess.db'

    @staticmethod
    def _get_connection():
        return sqlite3.connect(FileAccess()._db)

    @staticmethod
    def _get_cursor(conn):
        return conn.cursor()

    def get_file(self, file_name):

        conn = FileAccess._get_connection()
        cursor = FileAccess._get_cursor(conn)
        cursor.execute('SELECT * FROM permissions WHERE filename=?', (file_name,))
        row = cursor.fetchone()
        conn.close()

        if not row:
            return 'No permission to read file'

        access = row[2]
        if access == 0 or access > os.getuid():
            return open(file_name).read()


